import Foundation

/// Запрос команды
struct BluetoothCommandRequest {
    /// Регистр основной команды
    let type: BluetoothCommandType?
    /// Посылаемая команда
    let command: BluetoothCommandOperation
    /// Дополнительные данные
    let payload: [UInt8]?

    /// Инициализатор
    /// - Parameters:
    ///   - type: Регистр основной команды
    ///   - command: Посылаемая команда
    ///   - payload: Дополнительные данные
    init(type: BluetoothCommandType? = nil, command: BluetoothCommandOperation, payload: [UInt8]? = nil) {
        self.type = type
        self.command = command
        self.payload = payload
    }
}

protocol BluetoothCommandRequestProvider {

    var request: BluetoothCommandRequestBuilder<BluetoothCommandRequest> { get }
}

struct BluetoothCommandRequestBuilder<T> {

    public typealias Builder = ([UInt8]) -> [Data]

    private var build: Builder

    public init(builder: @escaping Builder) {
        build = builder
    }

    public func convert(_ request: [UInt8]) -> [Data] {
        return build(request)
    }
}

protocol BluetoothRequestPackage: BluetoothCommandRequestProvider {
    /// Запрос
    var request: BluetoothCommandRequest { get }
    /// Данные запроса
    var commandData: [UInt8] { get }
}

extension BluetoothRequestPackage where Self: BluetoothCommandRequestConfigurator {

    var commandData: [UInt8] {
        var result: [UInt8] = []

        if let type = request.type {
            result += type.rawValue.asBytes
        }
        result += request.command.rawValue.asBytes

        if request.type == .writeVirtualString {
            if let payloadLength = request.payload?.count {
                result += UInt32(payloadLength).asBytes
            } else {
                result += [0]
            }
        }

        if let payload = request.payload {
            result += payload
        }

        return result
    }

    func requestPackage() -> [Data] {
        let data = request.convert(commandData)
        return data
    }
}

protocol BluetoothCommandRequestConfigurator {

    func requestPackage() -> [Data]
}

