import Foundation

/// Возвращает спектр
struct SpectrumCommand: BluetoothCommand {

    /// Формат Спектра
    let specFormatVersion: Bool

    let request = BluetoothCommandRequest(
        type: .readVirtualString,
        command: .spectrum
    )
}

// MARK: - Response

extension SpectrumCommand {

    private enum SpectrumValidationError: Error {
        case zeroTime
        case emptyPulses
    }

    private enum SpectrumParseError: Error {
        case nonValidCoefficients
        case legacy256Format
        case unexpectedLength
    }

    struct Response: Equatable {
        let time: UInt32
        let coefficients: [Float]
        let countNeg: UInt32?
        let pulses: [UInt32]
    }

    private enum Consts {
        static let spectrumCoeffecientCount = 3
        static let defaultOffset = spectrumCoeffecientCount + 1
        static let maxSpectrumChannels = 1024
        static let zipSpectrumChannels = 256
        static let dataSize = (defaultOffset + maxSpectrumChannels) * 4
        static let dataSize256 = (defaultOffset + zipSpectrumChannels) * 4
        static let seed = 117
    }

    var response: BluetoothCommandResponseBuilder<Response> {
        .init { storage in
            let bytes = storage.body

            do {
                let time: UInt32 = bytes.toBinaryInteger(start: 0)

                guard time > 0 else {
                    throw SpectrumValidationError.zeroTime
                }

                let coefficients: [Float] = [
                    bytes.toFloat(start: 4),
                    bytes.toFloat(start: 8),
                    bytes.toFloat(start: 12)
                ]

                guard CalibrationCoefficients(coefficients: coefficients).isValid else {
                    throw SpectrumParseError.nonValidCoefficients
                }

                var countNeg: UInt32?
                var pulses: [UInt32] = []

                if specFormatVersion {
                    countNeg = bytes.toBinaryInteger(start: 16)
                    pulses = try SpectrumPulseConverter.spectrumZip(bytes: Array(bytes.dropFirst(20)))
                } else {
                    switch bytes.count {
                    case Consts.dataSize:
                        for index in 0..<Consts.dataSize {
                            pulses[index] = bytes.toBinaryInteger(start: (Consts.defaultOffset + index) * 4)
                        }
                    case Consts.dataSize256:
                        throw SpectrumParseError.legacy256Format
                        /// Парсинг данного спектра не актуален и не работает

                        //                    let storageString = storage.body.map {"\($0)"}.joined(separator: ",")
                        //                    storageString.components(withLength: 90).forEach { part in
                        //                        Analytics.logEvent(
                        //                            "SpectrumCommand_Response",
                        //                            parameters: ["Storage": part]
                        //                        )
                        //                    }
                        //                    coefficients[1] *= 4
                        //                    coefficients[2] *= 16
                        //
                        //                    var generator: RandomNumberGenerator = RandomNumberGeneratorWithSeed(seed: Consts.seed)
                        //
                        //                    for index in 0..<Consts.dataSize256 {
                        //                        let source: UInt32 = bytes.toBinaryInteger(start: (Consts.defaultOffset + index) * 4)
                        //                        let convertedValues = convert(generator: &generator, source: source)
                        //                        let i4: Int = index * 4
                        //                        pulses[i4] = convertedValues[0]
                        //                        pulses[i4 + 1] = convertedValues[1]
                        //                        pulses[i4 + 2] = convertedValues[2]
                        //                        pulses[i4 + 3] = convertedValues[3]
                        //                    }
                    default:
                        throw SpectrumParseError.unexpectedLength
                    }
                }

                guard pulses.contains(where: { $0 > 0 }) else {
                    throw SpectrumValidationError.emptyPulses
                }

                let spectrum = Response(
                    time: time,
                    coefficients: coefficients,
                    countNeg: countNeg,
                    pulses: pulses
                )

                return spectrum

            } catch {
                switch error {
                case is SpectrumParseError,
                     is SpectrumPulseConverter.SpectrumDecodeError:
                    throw CommandError(storage: storage, error: error)
                default:
                    throw error
                }
            }
        }
    }
}

