//  SpectrumPulseConverter.swift
//  Radiacode
//
//  Created by Matvey Kozin on 11.04.2024.
//

import Foundation

final class SpectrumPulseConverter {

    enum SpectrumDecodeError: Error {
        case outOfBounds
        case negativeAccumulator(Int)
        case unknownMethod
    }

    private enum Consts {
        static let maxSpectrumChannels = 1024
    }
    // MARK: - Zip Spectrum

    private enum MethodId: Int {
        case MDID_DUP0
        case MDID_U07
        case MDID_S08
        case MDID_S16
        case MDID_S24
        case MDID_U32
        case unknown
    }

    static func spectrum256bit(generator: inout RandomNumberGenerator, source: UInt32) -> [UInt32] {
        let newPulses = source / 4
        var result: [UInt32] = (0...3).map { _ in newPulses }

        switch source % 4 {
        case 1:
            result[Int.random(in: 0...3, using: &generator)] += 1
        case 2:
            result[Int.random(in: 0...1, using: &generator)] += 1
            result[Int.random(in: 2...3, using: &generator)] += 1
        case 3:
            result = result.map { $0 + 1 }
            result[Int.random(in: 0...3, using: &generator)] -= 1
        default:
            break
        }
        return result
    }

    static func spectrumZip(bytes: [UInt8]) throws -> [UInt32] {

        // Последнее извлеченное значение
        var prevValue: Int = 0

        var result: [UInt32] = []

        var startIndex = 0
        var channelsSize = Consts.maxSpectrumChannels

        while (channelsSize > 0) {

            // Каждая подпоследовательность начинается с 2-байтного заголовка
            let header: UInt16 = bytes.toBinaryInteger(start: startIndex)
            startIndex += 2

            // Cтаршие 12 бит содержат количество каналов в подпоследовательности
            let size = Int((header >> 4) & 0xFFF)
            channelsSize -= size

            // Младшие 4 бита которого содержат идентификатор типа подпоследовательности
            let method: MethodId = MethodId(rawValue: Int(header & 0xF)) ?? .unknown

            switch method {
            case .MDID_DUP0:
                decodeDUP0(into: &result, size: size, prevValue: &prevValue)
            case .MDID_U07:
                try decodeU07(bytes, into: &result, size: size, startIndex: &startIndex, prevValue: &prevValue)
            case .MDID_S08:
                try decodeS08(bytes, into: &result, size: size, startIndex: &startIndex, prevValue: &prevValue)
            case .MDID_S16:
                try decodeS16(bytes, into: &result, size: size, startIndex: &startIndex, prevValue: &prevValue)
            case .MDID_S24:
                try decodeS24(bytes, into: &result, size: size, startIndex: &startIndex, prevValue: &prevValue)
            case .MDID_U32:
                try decodeU32(bytes, into: &result, size: size, startIndex: &startIndex, prevValue: &prevValue)
            case .unknown:
                throw SpectrumDecodeError.unknownMethod
            }
        }
        return result
    }

    private static func decodeDUP0(into result: inout [UInt32], size: Int, prevValue: inout Int) {
        for _ in 0..<size {
            result.append(0)
        }
        prevValue = 0
    }

    private static func decodeU07(_ bytes: [UInt8], into result: inout [UInt32], size: Int, startIndex: inout Int, prevValue: inout Int) throws {
        for _ in 0..<size {
            guard startIndex < bytes.count else { throw SpectrumDecodeError.outOfBounds }
            let value: UInt8 = bytes.toBinaryInteger(start: startIndex)
            prevValue = Int(value)
            result.append(UInt32(prevValue))
            startIndex += 1
        }
    }

    private static func decodeS08(_ bytes: [UInt8], into result: inout [UInt32], size: Int, startIndex: inout Int, prevValue: inout Int) throws {
        for _ in 0..<size {
            guard startIndex < bytes.count else { throw SpectrumDecodeError.outOfBounds }
            let value: Int8 = bytes.toBinaryInteger(start: startIndex)
            let next = prevValue &+ Int(value)

            guard next >= 0 else { throw SpectrumDecodeError.negativeAccumulator(next) }

            prevValue = next
            result.append(UInt32(prevValue))
            startIndex += 1
        }
    }

    private static func decodeS16(_ bytes: [UInt8], into result: inout [UInt32], size: Int, startIndex: inout Int, prevValue: inout Int) throws {
        for _ in 0..<size {
            guard startIndex + 1 < bytes.count else { throw SpectrumDecodeError.outOfBounds }

            let value: Int16 = bytes.toBinaryInteger(start: startIndex)
            let next = prevValue &+ Int(value)

            guard next >= 0 else { throw SpectrumDecodeError.negativeAccumulator(next) }

            prevValue = next
            result.append(UInt32(prevValue))
            startIndex += 2
        }
    }

    private static func decodeS24(_ bytes: [UInt8], into result: inout [UInt32], size: Int, startIndex: inout Int, prevValue: inout Int) throws {
        for _ in 0..<size {
            // Нужно 3 байта
            guard startIndex + 2 < bytes.count else { throw SpectrumDecodeError.outOfBounds }

            //  Читаем младшие 2 байта по указателю src, как числа без знака
            let firstPart: UInt16 = bytes.toBinaryInteger(start: startIndex)
            // Смещаем указатель на 3-й байт
            startIndex += 2
            // Читаем 3-й байт, как число со знаком
            let secondPart: Int8 = bytes.toBinaryInteger(start: startIndex)
            // преобразуем его в 4-байтное число со знаком (при этом старший бит прочитанного байта размножается во всех битах старших 3-х байтов)
            // сдвигаем полученное значение на 16 бит влево и объединяем побитным логическим or с прочитанными ранее 2-мя байтами
            let diff = Int32(firstPart) | (Int32(secondPart) << 16)
            let next = prevValue &+ Int(diff)

            guard next >= 0 else { throw SpectrumDecodeError.negativeAccumulator(next) }

            prevValue = next
            result.append(UInt32(prevValue))
            startIndex += 1
        }
    }

    private static func decodeU32(_ bytes: [UInt8], into result: inout [UInt32], size: Int, startIndex: inout Int, prevValue: inout Int) throws {
        for _ in 0..<size {
            guard startIndex + 3 < bytes.count else { throw SpectrumDecodeError.outOfBounds }
            // значения каналов передаются "как есть"
            let value: UInt32 = bytes.toBinaryInteger(start: startIndex)
            prevValue = Int(value)
            result.append(value)
            startIndex += 4
        }
    }
}

